const msg = $input.item.json;
const headers = (msg.payload && msg.payload.headers) ? msg.payload.headers : [];

function getHeader(name) {
  const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}

function decodeBase64(encoded) {
  if (!encoded) return '';
  // Convert base64url to standard base64
  let standardBase64 = encoded.replace(/-/g, '+').replace(/_/g, '/');
  // Pad with '=' if necessary
  while (standardBase64.length % 4) {
    standardBase64 += '=';
  }
  return Buffer.from(standardBase64, 'base64').toString('utf8');
}

function extractBodyText(payload) {
  if (!payload) return '';

  if (payload.body && payload.body.data) {
    return decodeBase64(payload.body.data);
  }

  if (payload.parts) {
    for (const part of payload.parts) {
      if (part.mimeType === 'text/plain' && part.body && part.body.data) {
        return decodeBase64(part.body.data);
      }
    }
    for (const part of payload.parts) {
      if (part.mimeType === 'text/html' && part.body && part.body.data) {
        return decodeBase64(part.body.data);
      }
    }
  }
  return '';
}

const subject = getHeader('Subject');
const from    = getHeader('From');
const snippet = msg.snippet || '';
const body    = extractBodyText(msg.payload);

return [{ json: { subject, from, snippet, text: body, body, html: body } }];

const text = $input.item.json.text || "";
const html = $input.item.json.html || "";
const combined = text + "\n" + html;

// Look for the "En savoir plus :" link or the raw activity link
const regex = /https:\/\/(?:www\.)?linkedin\.com\/comm\/feed\/update\/urn:li:activity:\d+/i;
const match = combined.match(regex);

if (match && match[0]) {
  return [{ json: { ...$input.item.json, post_url: match[0] } }];
}

// Fallback: Look for the standard LinkedIn share link structure
const standardRegex = /https:\/\/(?:www\.)?linkedin\.com\/comm\/posts\/[^\s\"\'<>]+/i;
const standardMatch = combined.match(standardRegex);

if (standardMatch && standardMatch[0]) {
  let url = standardMatch[0];
  url = url.replace(/&amp;/g, '&');
  return [{ json: { ...$input.item.json, post_url: url } }];
}

// If we STILL can't find it, dump the text again
return [{ json: { skip: true, reason: 'Could not find url. Email body was: ' + combined.substring(0, 500) } }];

const finalUrl = $input.item.json.url || "";
const html = $input.item.json.data || "";

// 1. Find the URN
const urnRegex = /urn:li:(?:activity|ugcPost|share):\d+/;
const urnMatch = html.match(urnRegex);
let threadUrn = "";

if (urnMatch) {
  threadUrn = urnMatch[0];
  threadUrn = threadUrn.replace(":ugcPost:", ":activity:").replace(":share:", ":activity:");
}

// 2. Extract FULL Untruncated Post Text from LinkedIn's background HTML SEO
let fullPostText = "";

try {
  // Try to find LinkedIn's hidden JSON-LD structure
  const ldRegex = /<script type=["']application\/ld\+json["']>(.*?)<\/script>/gis;
  let match;
  while ((match = ldRegex.exec(html)) !== null) {
    try {
      const jsonLd = JSON.parse(match[1].trim());
      if (jsonLd.articleBody) {
        fullPostText = jsonLd.articleBody;
        break;
      }
    } catch(e) {}
  }
} catch(e) {}

// 3. Fallback: Check standard HTML Meta Description tags
if (!fullPostText) {
  const ogRegex = /<meta\s+(?:property|name)=["'](?:og:)?description["']\s+content=["']([^"']+)["']/i;
  const ogMatch = html.match(ogRegex);
  if (ogMatch && ogMatch[1]) {
    fullPostText = ogMatch[1]
      .replace(/&quot;/g, '"')
      .replace(/&amp;/g, '&')
      .replace(/&#39;/g, "'")
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>');
  }
}

// 4. Last Resort: Use the email snippet preview if LinkedIn blocked the page download
if (!fullPostText) {
  let emailText = $("Parse Gmail Message").item.json.text || "";
  const textMatch = emailText.match(/(?:partagé un post|a publié|nouvelle publication)\s*:([\s\S]*?)(?:En savoir plus|Afficher le post|View post|Voir le post)/i);
  if (textMatch && textMatch[1]) {
    fullPostText = textMatch[1].trim();
  } else {
    fullPostText = emailText; 
  }
}

return [{
  json: {
    post_url: finalUrl,
    threadUrn: threadUrn,
    author: $("Parse Gmail Message").item.json.from.split("<")[0].trim(),

    // Pass the FULL text string down to the AI Agent!
    post_text: fullPostText
  }
}];

